const merged = $json;
const jd = merged.jd || {};
const entries = merged.resume_entries || [];

const entryLines = entries.length
  ? entries.map((e) => `- [${e.category}] ${e.canonical_text} (tags: ${(e.tags || []).join(', ')})`).join('\n')
  : '(no resume entries on file)';

const profileLines = [
  `Long-term goals: ${merged.long_term_goals || '(none)'}`,
  `Target role types: ${(merged.target_role_types || []).join(', ')}`,
].join('\n');

const jdLines = [
  `Role: ${jd.role_title || merged.role_title || 'unknown'} (team: ${jd.team_or_org || 'unspecified'})`,
  `Company: ${jd.company_name || merged.company_name || 'unknown'}`,
  `Must-haves: ${(jd.must_haves || []).join(', ')}`,
  `Nice-to-haves: ${(jd.nice_to_haves || []).join(', ')}`,
  `Responsibilities: ${(jd.responsibilities || []).join(', ')}`,
  `Tech stack: ${(jd.tech_stack || []).join(', ')}`,
  `Culture signals: ${(jd.culture_signals || []).join(', ')}`,
  `Location type: ${jd.location_type || 'unknown'}`,
].join('\n');

const synthesis = merged.company_synthesis || {};
const synthesisLines = [
  `What they do: ${synthesis.what_they_do || '(unavailable)'}`,
  `Recent developments: ${(synthesis.recent_developments || []).join(', ')}`,
  `Tech signals: ${(synthesis.tech_signals || []).join(', ')}`,
  `Company type: ${synthesis.company_type || 'unknown'}`,
  `Culture signals: ${(synthesis.culture_signals || []).join(', ')}`,
  `Likely role context: ${synthesis.likely_role_context || '(unavailable)'}`,
].join('\n');

const critic_prompt = [
  "## Candidate's master resume entries",
  entryLines,
  "## Candidate's profile",
  profileLines,
  '## Job description',
  jdLines,
  '## Company research synthesis',
  synthesisLines,
].join('\n\n').slice(0, 12000);

return [{
  json: {
    application_id: merged.application_id,
    role_title: jd.role_title || merged.role_title,
    company_name: jd.company_name || merged.company_name,
    jd,
    resume_entries: entries,
    long_term_goals: merged.long_term_goals,
    target_role_types: merged.target_role_types,
    critic_prompt,
  },
}];

const critic = JSON.parse($input.item.json.text);
const prior = $('Prepare Critic Input').item.json;
return [{
  json: {
    ...prior,
    critic,
    critic_json: JSON.stringify(critic),
  },
}];

const prior = $('Parse Critic Output').item.json;
const { critic, jd, role_title, company_name, long_term_goals, target_role_types } = prior;

const profileLines = [
  `Long-term goals: ${long_term_goals || '(none)'}`,
  `Target role types: ${(target_role_types || []).join(', ')}`,
].join('\n');

const bullets = (items) => (items && items.length) ? items.map((i) => `- ${i}`).join('\n') : '(none)';

const criticLines = [
  'Strengths for this role:',
  bullets(critic.strengths_for_this_role),
  'Weaknesses to address:',
  bullets(critic.weaknesses_to_address),
  'Gaps unfixable in this application:',
  bullets(critic.gaps_unfixable_in_this_application),
  `Suggested angle: ${critic.suggested_angle}`,
].join('\n');

const jdLines = [
  `Role: ${jd.role_title || role_title || 'unknown'} (team: ${jd.team_or_org || 'unspecified'})`,
  `Company: ${jd.company_name || company_name || 'unknown'}`,
  `Must-haves: ${(jd.must_haves || []).join(', ')}`,
  `Nice-to-haves: ${(jd.nice_to_haves || []).join(', ')}`,
  `Responsibilities: ${(jd.responsibilities || []).join(', ')}`,
  `Tech stack: ${(jd.tech_stack || []).join(', ')}`,
  `Culture signals: ${(jd.culture_signals || []).join(', ')}`,
  `Location type: ${jd.location_type || 'unknown'}`,
].join('\n');

const scorer_prompt = [
  '## Resume Critic output',
  criticLines,
  '## Job description',
  jdLines,
  "## Candidate's profile",
  profileLines,
].join('\n\n').slice(0, 12000);

return [{ json: { ...prior, scorer_prompt } }];

const scorer = JSON.parse($input.item.json.text);
const prior = $('Prepare Scorer Input').item.json;
return [{
  json: {
    ...prior,
    scorer,
    scorer_json: JSON.stringify(scorer),
    score: scorer.score,
  },
}];

const prior = $('Parse Scorer Output').item.json;
const scorer = prior.scorer;
const resumeUrl = $execution.resumeUrl;

const gapLines = (scorer.top_gaps && scorer.top_gaps.length)
  ? scorer.top_gaps.map((g) => `- ${g.gap} (${g.severity})`).join('\n')
  : '(none)';

const lines = [
  `*Low match: ${scorer.score}/100 (${scorer.tier})* for *${prior.role_title}* @ *${prior.company_name}*`,
  '',
  scorer.reasoning,
  '',
  '*Top gaps:*',
  gapLines,
];

if (scorer.red_flags && scorer.red_flags.length) {
  lines.push('', '*Red flags:*', scorer.red_flags.map((r) => `- ${r}`).join('\n'));
}

lines.push('', `<${resumeUrl}?action=continue|Continue anyway>  |  <${resumeUrl}?action=skip|Skip this one>`);

return [{ json: { slack_text: lines.join('\n') } }];

let priorGrounding = null;
try {
  priorGrounding = $('Parse Grounding Output').item.json;
} catch (e) {
  priorGrounding = null;
}

const prior = priorGrounding || $('Parse Scorer Output').item.json;
const { critic, jd, resume_entries, application_id, role_title, company_name, scorer } = prior;

const entryLines = (resume_entries && resume_entries.length)
  ? resume_entries.map((e) => `- id=${e.id} [${e.category}] ${e.canonical_text} (tags: ${(e.tags || []).join(', ')})`).join('\n')
  : '(no resume entries on file)';

const jdLines = [
  `Role: ${jd.role_title || role_title || 'unknown'} (team: ${jd.team_or_org || 'unspecified'})`,
  `Company: ${jd.company_name || company_name || 'unknown'}`,
  `Must-haves: ${(jd.must_haves || []).join(', ')}`,
  `Nice-to-haves: ${(jd.nice_to_haves || []).join(', ')}`,
  `Responsibilities: ${(jd.responsibilities || []).join(', ')}`,
  `Tech stack: ${(jd.tech_stack || []).join(', ')}`,
].join('\n');

let tailorer_prompt = [
  "## Candidate's master resume entries (each has an id you must reference)",
  entryLines,
  '## Job description',
  jdLines,
  `## Suggested angle\n${critic.suggested_angle}`,
].join('\n\n');

const retryCount = priorGrounding ? (priorGrounding.retry_count || 0) + 1 : 0;

if (priorGrounding && priorGrounding.grounding) {
  const violations = priorGrounding.grounding.violations || [];
  tailorer_prompt += '\n\n## Revision feedback (previous attempt failed grounding check)\n' +
    'Fix these grounding violations — every claim must trace to the cited master_resume_entry_id with no invented details:\n' +
    violations.map((v) => `- ${v}`).join('\n');
}

return [{
  json: {
    application_id,
    role_title: jd.role_title || role_title,
    company_name: jd.company_name || company_name,
    critic,
    jd,
    resume_entries,
    scorer,
    tailorer_prompt: tailorer_prompt.slice(0, 12000),
    retry_count: retryCount,
  },
}];

const resp = $input.item.json;
const tailored = JSON.parse(resp.text);
const prior = $('Prepare Tailorer Input').item.json;
return [{
  json: {
    ...prior,
    tailored,
    tailored_json: JSON.stringify(tailored),
    model_used: resp.model,
  },
}];

const prior = $json;
const { tailored, resume_entries } = prior;

const entriesById = {};
for (const e of (resume_entries || [])) entriesById[e.id] = e;

const blocks = [];
let n = 0;
for (const section of (tailored.sections || [])) {
  for (const line of (section.lines || [])) {
    n += 1;
    const entry = entriesById[line.master_resume_entry_id];
    const sourceText = entry ? entry.canonical_text : '(no entry with this id was provided)';
    blocks.push(
      `Line ${n} [${section.category}] (from ${line.master_resume_entry_id})\n` +
      `Tailored: "${line.text}"\n` +
      `Source (${line.master_resume_entry_id}): "${sourceText}"`
    );
  }
}

const grounding_prompt = [
  '## Lines to check\nEach numbered item pairs one tailored-resume line with the exact source entry it claims to be drawn from. Check each line only against its own paired source.',
  ...blocks,
  `## Summary to check\nTailored summary: "${tailored.summary}"\nCheck the summary against the union of all source entries above — it should not introduce facts beyond what they support.`,
].join('\n\n').slice(0, 12000);

return [{ json: { ...prior, grounding_prompt } }];

const grounding = JSON.parse($input.item.json.text);
const prior = $('Prepare Grounding Check').item.json;
return [{ json: { ...prior, grounding } }];

const prior = $json;
const grounding = prior.grounding;
const violationLines = (grounding.violations && grounding.violations.length)
  ? grounding.violations.map((v) => `- ${v}`).join('\n')
  : '(none listed)';

const text = [
  `*Grounding check failed twice for ${prior.role_title} @ ${prior.company_name}.*`,
  'The tailored resume still has unsupported claims after one retry:',
  violationLines,
  '',
  'No tailored resume was saved for this application — review the master resume entries and tailorer prompt manually.',
].join('\n');

return [{ json: { slack_text: text } }];

const materialId = $json.id;
const prior = $('Parse Tailored Resume').item.json;
const tailored = prior.tailored;

const rows = [];
for (const section of (tailored.sections || [])) {
  for (const line of (section.lines || [])) {
    rows.push({
      json: {
        material_id: materialId,
        master_entry_id: line.master_resume_entry_id,
        usage_note: line.text,
      },
    });
  }
}
return rows;

const prior = $('Parse Tailored Resume').item.json;
const materialId = $('Persist Tailored Resume').item.json.id;
return [{
  json: {
    application_id: prior.application_id,
    role_title: prior.role_title,
    company_name: prior.company_name,
    material_id: materialId,
    scorer: prior.scorer,
    tailored: prior.tailored,
  },
}];

const prior = $json;
const tailorerInput = $('Prepare Tailorer Input').item.json;
const merged = $('Merge Inputs').item.json;
const { critic, jd, resume_entries } = tailorerInput;
const synthesis = merged.company_synthesis || {};

const entryLines = (resume_entries && resume_entries.length)
  ? resume_entries.map((e) => `- id=${e.id} [${e.category}] ${e.canonical_text} (tags: ${(e.tags || []).join(', ')})`).join('\n')
  : '(no resume entries on file)';

const jdLines = [
  `Role: ${jd.role_title || prior.role_title || 'unknown'} (team: ${jd.team_or_org || 'unspecified'})`,
  `Company: ${jd.company_name || prior.company_name || 'unknown'}`,
  `Must-haves: ${(jd.must_haves || []).join(', ')}`,
  `Nice-to-haves: ${(jd.nice_to_haves || []).join(', ')}`,
  `Responsibilities: ${(jd.responsibilities || []).join(', ')}`,
  `Tech stack: ${(jd.tech_stack || []).join(', ')}`,
  `Culture signals: ${(jd.culture_signals || []).join(', ')}`,
  `Location type: ${jd.location_type || 'unknown'}`,
].join('\n');

const synthesisLines = [
  `What they do: ${synthesis.what_they_do || '(unavailable)'}`,
  `Recent developments: ${(synthesis.recent_developments || []).join(', ')}`,
  `Tech signals: ${(synthesis.tech_signals || []).join(', ')}`,
  `Company type: ${synthesis.company_type || 'unknown'}`,
  `Culture signals: ${(synthesis.culture_signals || []).join(', ')}`,
  `Likely role context: ${synthesis.likely_role_context || '(unavailable)'}`,
].join('\n');

const profileLines = [
  `Long-term goals: ${merged.long_term_goals || '(none)'}`,
  `Target role types: ${(merged.target_role_types || []).join(', ')}`,
].join('\n');

const cover_letter_prompt = [
  "## Candidate's master resume entries (each has an id you must reference)",
  entryLines,
  '## Job description',
  jdLines,
  '## Company research synthesis',
  synthesisLines,
  `## Suggested angle\n${critic.suggested_angle}`,
  "## Candidate's profile",
  profileLines,
].join('\n\n').slice(0, 12000);

return [{
  json: {
    application_id: prior.application_id,
    role_title: prior.role_title,
    company_name: prior.company_name,
    material_id: prior.material_id,
    scorer: prior.scorer,
    tailored: prior.tailored,
    jd,
    resume_entries,
    company_synthesis: synthesis,
    critic,
    cover_letter_prompt,
  },
}];

const coverLetter = JSON.parse($input.item.json.text);
const prior = $('Prepare Cover Letter Input').item.json;

// qwen2.5:7b reliably ignores the prompt instruction not to inline grounding
// citations (e.g. "(id=<uuid>)", "(from <uuid>)") into cover letter prose, so
// strip them here as a backstop.
const CITATION_RE = /\s*[\(\[]\s*(?:ids?\s*[:=]\s*[\w-]+|from\s+[\w]+-[\w-]+)(?:\s*,\s*(?:ids?\s*[:=]\s*)?[\w-]+)*\s*[\)\]]/gi;
coverLetter.paragraphs = (coverLetter.paragraphs || []).map((p) =>
  p.replace(CITATION_RE, '').replace(/\s{2,}/g, ' ').replace(/\s+([.,;:])/g, '$1').trim()
);

return [{
  json: {
    ...prior,
    cover_letter: coverLetter,
    cover_letter_json: JSON.stringify(coverLetter),
    cover_letter_model_used: $input.item.json.model,
  },
}];

const prior = $('Parse Cover Letter Output').item.json;
const coverLetter = prior.cover_letter;
const materialId = $json.id;
const ids = coverLetter.master_resume_entry_ids || [];

return ids.map((entryId) => ({
  json: {
    material_id: materialId,
    master_entry_id: entryId,
    usage_note: `Referenced in cover letter (${coverLetter.company_detail_referenced || ''})`.trim(),
  },
}));

const prior = $('Parse Cover Letter Output').item.json;
const { jd, company_synthesis, critic } = prior;
const synthesis = company_synthesis || {};

const jdLines = [
  `Role: ${jd.role_title || prior.role_title || 'unknown'} (team: ${jd.team_or_org || 'unspecified'})`,
  `Company: ${jd.company_name || prior.company_name || 'unknown'}`,
  `Must-haves: ${(jd.must_haves || []).join(', ')}`,
  `Nice-to-haves: ${(jd.nice_to_haves || []).join(', ')}`,
  `Responsibilities: ${(jd.responsibilities || []).join(', ')}`,
  `Tech stack: ${(jd.tech_stack || []).join(', ')}`,
  `Culture signals: ${(jd.culture_signals || []).join(', ')}`,
  `Location type: ${jd.location_type || 'unknown'}`,
].join('\n');

const synthesisLines = [
  `What they do: ${synthesis.what_they_do || '(unavailable)'}`,
  `Recent developments: ${(synthesis.recent_developments || []).join(', ')}`,
  `Tech signals: ${(synthesis.tech_signals || []).join(', ')}`,
  `Company type: ${synthesis.company_type || 'unknown'}`,
  `Culture signals: ${(synthesis.culture_signals || []).join(', ')}`,
  `Likely role context: ${synthesis.likely_role_context || '(unavailable)'}`,
].join('\n');

const linkedin_prompt = [
  '## Job description',
  jdLines,
  '## Company research synthesis',
  synthesisLines,
  `## Suggested angle\n${critic.suggested_angle}`,
].join('\n\n').slice(0, 12000);

return [{ json: { ...prior, linkedin_prompt } }];

const linkedin = JSON.parse($input.item.json.text);
const prior = $('Prepare LinkedIn Input').item.json;
return [{
  json: {
    ...prior,
    linkedin,
    linkedin_json: JSON.stringify(linkedin),
    linkedin_model_used: $input.item.json.model,
  },
}];

const prior = $('Parse LinkedIn Output').item.json;
const merged = $('Merge Inputs').item.json;
const { jd, critic } = prior;

const bullets = (items) => (items && items.length) ? items.map((i) => `- ${i}`).join('\n') : '(none)';

const criticLines = [
  'Strengths for this role:',
  bullets(critic.strengths_for_this_role),
  'Weaknesses to address:',
  bullets(critic.weaknesses_to_address),
  'Gaps unfixable in this application:',
  bullets(critic.gaps_unfixable_in_this_application),
  `Suggested angle: ${critic.suggested_angle}`,
].join('\n');

const profileLines = [
  `Long-term goals: ${merged.long_term_goals || '(none)'}`,
  `Target role types: ${(merged.target_role_types || []).join(', ')}`,
].join('\n');

const skill_gap_prompt = [
  '## Job description must-haves and nice-to-haves',
  `Must-haves: ${(jd.must_haves || []).join(', ')}`,
  `Nice-to-haves: ${(jd.nice_to_haves || []).join(', ')}`,
  '## Resume Critic output',
  criticLines,
  "## Candidate's profile",
  profileLines,
].join('\n\n').slice(0, 12000);

return [{ json: { ...prior, skill_gap_prompt } }];

const skillGap = JSON.parse($input.item.json.text);
const prior = $('Prepare Skill Gap Input').item.json;
return [{
  json: {
    ...prior,
    skill_gap: skillGap,
    skill_gap_json: JSON.stringify(skillGap),
    skill_gap_model_used: $input.item.json.model,
  },
}];

const finalize = $('Finalize Material').item.json;
const company = finalize.company_name || 'company';
const role = finalize.role_title || 'role';
const today = new Date().toISOString().slice(0, 10);

const sanitize = (s) => String(s).trim().replace(/[^a-zA-Z0-9]+/g, '_').replace(/^_+|_+$/g, '');

return [{
  json: {
    drive_folder_name: `${sanitize(company)}_${sanitize(role)}_${today}`,
  },
}];

const tailored = $('Finalize Material').item.json.tailored;
const folderId = $json.id;

return [{
  json: {
    drive_folder_id: folderId,
    drive_folder_url: `https://drive.google.com/drive/folders/${folderId}`,
    render_resume_body: {
      template: 'resume',
      data: { summary: tailored.summary, sections: tailored.sections },
    },
  },
}];

const coverLetter = $('Parse Cover Letter Output').item.json;
const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

return [{
  json: {
    drive_folder_id: $('Prepare Resume PDF Data').item.json.drive_folder_id,
    resume_drive_url: $json.webViewLink,
    render_cover_letter_body: {
      template: 'cover_letter',
      data: {
        company_name: coverLetter.company_name,
        role_title: coverLetter.role_title,
        date: today,
        paragraphs: coverLetter.cover_letter.paragraphs,
      },
    },
  },
}];

return [{
  json: {
    resume_material_id: $('Finalize Material').item.json.material_id,
    resume_drive_url: $('Prepare Cover Letter PDF Data').item.json.resume_drive_url,
    cover_letter_material_id: $('Persist Cover Letter').item.json.id,
    cover_letter_drive_url: $json.webViewLink,
  },
}];

const finalize = $('Finalize Material').item.json;
const scorer = finalize.scorer || {};
const skillGap = $('Parse Skill Gap Output').item.json.skill_gap || {};
const linkedin = $('Parse LinkedIn Output').item.json.linkedin || {};
const jdUrl = $('Load JD URL').item.json.url;
const pdfUrls = $('Prepare PDF URL Updates').item.json;

const richText = (s) => [{ type: 'text', text: { content: String(s ?? '').slice(0, 2000) } }];

const properties = {
  Name: { title: richText(`${finalize.company_name} — ${finalize.role_title}`) },
  Company: { rich_text: richText(finalize.company_name) },
  'Role Title': { rich_text: richText(finalize.role_title) },
  'Application ID': { rich_text: richText(finalize.application_id) },
  Status: { select: { name: 'awaiting_review' } },
  'Match Score': { number: scorer.score ?? null },
  'Match Tier': { select: { name: scorer.tier || 'unknown' } },
  'Skill Gap Verdict': { select: { name: skillGap.verdict || 'unknown' } },
  'JD URL': { url: jdUrl || null },
  'Resume PDF': { url: pdfUrls.resume_drive_url || null },
  'Cover Letter PDF': { url: pdfUrls.cover_letter_drive_url || null },
  'LinkedIn Message': { rich_text: richText(linkedin.message) },
  Created: { date: { start: new Date().toISOString().slice(0, 10) } },
};

return [{
  json: {
    notion_body: {
      parent: { database_id: '3806af3e78ea805fb6b8d1ca4c58188b' },
      properties,
    },
  },
}];

const prior = $('Finalize Material').item.json;
const extra = $('Parse Skill Gap Output').item.json;
const scorer = prior.scorer || {};
const skillGap = extra.skill_gap || {};
const driveFolderUrl = $('Prepare Resume PDF Data').item.json.drive_folder_url;
const notionUrl = $('Create Notion Page').item.json.url;

const text = [
  `*Tailored resume ready for review:* ${prior.role_title} @ ${prior.company_name}`,
  `Match score: ${scorer.score}/100 (${scorer.tier})`,
  `Summary: ${prior.tailored.summary}`,
  '',
  'Cover letter, LinkedIn message, and skill-gap report generated.',
  `Skill gap verdict: ${skillGap.verdict || 'unknown'}`,
  '',
  `Drive folder: ${driveFolderUrl}`,
  `Notion page: ${notionUrl}`,
  '',
  'Status set to awaiting_review — review the materials and submit manually.',
].join('\n');

return [{ json: { slack_text: text } }];
